) {
  verify_pq(physeq)

  rar_once <- function(s) {
    .rarefy_even_depth_pq(
      physeq,
      sample_size,
      rngseed = s,
      replace = replace,
      trimOTUs = FALSE
    )
  }

  if (n <= 1) {
    return(rar_once(seed))
  }

  set.seed(seed)
  seeds <- sample.int(.Machine$integer.max, n)
  reps <- lapply(seeds, rar_once)

  # Average OTU tables across repetitions
  mats <- lapply(reps, function(p) as(otu_table(p), "matrix"))
  avg <- Reduce("+", mats) / n

  new_physeq <- reps[[1]]
  new_physeq@otu_table <- otu_table(
    avg,
    taxa_are_rows = taxa_are_rows(reps[[1]])
  )
  return(new_physeq)
}

# Internal: R-version-robust drop-in for phyloseq::rarefy_even_depth(). Its
# argument defaults (`rngseed = FALSE`, `replace = TRUE`, `trimOTUs = TRUE`)
# match phyloseq's, so `phyloseq::rarefy_even_depth(physeq, rngseed = i)` can be
# swapped for `.rarefy_even_depth_pq(physeq, rngseed = i)` verbatim. It
# reproduces phyloseq's RNG save/restore, its pruning of samples with fewer
# reads than `sample_size`, its per-sample subsampling for both `replace`
# modes, and its optional trimming of emptied OTUs — but avoids the fragile
# `rep_len(x["OTUi"], x["times"])` construct that errors under recent R-devel
# (phyloseq issue #1753). Bit-identical to phyloseq except in the degenerate
# single-read case where phyloseq hits a `sample()` edge-case bug.
.rarefy_even_depth_pq <- function(
  physeq,
  sample_size = NULL,
  rngseed = FALSE,
  replace = TRUE,
  trimOTUs = TRUE
) {
  # Match phyloseq: when rngseed is set, save the caller's RNG state, seed, and
  # restore the state on exit so the global RNG stream is left untouched.
  if (isTRUE(as.logical(rngseed))) {
    if (exists(".Random.seed", envir = globalenv(), inherits = FALSE)) {
      old_seed <- get(".Random.seed", envir = globalenv())
      on.exit(
        assign(".Random.seed", old_seed, envir = globalenv()),
        add = TRUE
      )
    }
    set.seed(rngseed)
  }
  if (is.null(sample_size)) {
    sample_size <- min(sample_sums(physeq))
  }
  sample_size <- as.integer(sample_size)
  if (is.na(sample_size) || sample_size <= 0) {
    stop("`sample_size` must be a positive integer.")
  }

  taxa_rows <- taxa_are_rows(physeq)
  otu <- as(otu_table(physeq), "matrix")
  if (!taxa_rows) {
    otu <- t(otu)
  }
  # Drop samples with fewer reads than `sample_size`
  keep <- colSums(otu) >= sample_size
  otu <- otu[, keep, drop = FALSE]

  subsample <- function(x) {
    if (replace) {
      idx <- suppressWarnings(
        sample(seq_along(x), sample_size, replace = TRUE, prob = x)
      )
    } else {
      expanded <- rep(seq_along(x), times = as.integer(x))
      idx <- expanded[sample.int(length(expanded), sample_size)]
    }
    tabulate(idx, nbins = length(x))
  }

  new_otu <- apply(otu, 2, subsample)
  if (is.null(dim(new_otu))) {
    new_otu <- matrix(new_otu, nrow = nrow(otu))

