  # Match phyloseq: when rngseed is set, save the caller's RNG state, seed, and
  # restore the state on exit so the global RNG stream is left untouched.
  if (isTRUE(as.logical(rngseed))) {
    if (exists(".Random.seed", envir = globalenv(), inherits = FALSE)) {
